package auth

import "context"

type contextKey struct{}

// SetClaims stores JWT claims in the context.
func SetClaims(ctx context.Context, claims *Claims) context.Context {
	return context.WithValue(ctx, contextKey{}, claims)
}

// GetClaims retrieves JWT claims from the context. Returns nil if not present.
func GetClaims(ctx context.Context) *Claims {
	claims, _ := ctx.Value(contextKey{}).(*Claims)
	return claims
}

// MustGetClaims retrieves JWT claims from the context.
// Panics if claims are not present — only call this in handlers behind auth middleware.
func MustGetClaims(ctx context.Context) *Claims {
	claims := GetClaims(ctx)
	if claims == nil {
		panic("auth: claims not found in context — handler must be behind auth middleware")
	}
	return claims
}

package middleware

import (
	"log/slog"
	"net/http"
	"strings"

	"github.com/ketang/kapow/api/internal/auth"
)

// Auth validates the Bearer JWT token from the Authorization header.
// On success, claims are stored in the request context via auth.SetClaims.
// On failure, responds with 401 Unauthorized.
func Auth(validator auth.Validator) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				slog.WarnContext(r.Context(), "auth: missing or malformed authorization header",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="kapow", resource_metadata="/.well-known/oauth-protected-resource"`)
				http.Error(w, "missing or malformed authorization header", http.StatusUnauthorized)
				return
			}

			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="kapow", error="invalid_token", resource_metadata="/.well-known/oauth-protected-resource"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			slog.DebugContext(r.Context(), "auth: token validated",
				"request_id", requestIDFromContext(r.Context()),
				"subject", claims.Subject,
			)
			ctx := auth.SetClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// OptionalAuth validates a Bearer token if present but allows unauthenticated requests.
// If a token is present and valid, claims are stored in context via auth.SetClaims.
// If a token is present but invalid, responds with 401 Unauthorized.
// If no token is present, the request proceeds without claims.
func OptionalAuth(validator auth.Validator) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				// No bearer token — allow anonymous access.
				next.ServeHTTP(w, r)
				return
			}

			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="kapow", error="invalid_token", resource_metadata="/.well-known/oauth-protected-resource"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			slog.DebugContext(r.Context(), "auth: token validated",
				"request_id", requestIDFromContext(r.Context()),
				"subject", claims.Subject,
			)
			ctx := auth.SetClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// bearerToken extracts the token from "Authorization: Bearer <token>".
func bearerToken(r *http.Request) (string, bool) {
	header := r.Header.Get("Authorization")
	if header == "" {
		return "", false
	}
	parts := strings.SplitN(header, " ", 2)
	if len(parts) != 2 || !strings.EqualFold(parts[0], "bearer") {
		return "", false
	}
	token := strings.TrimSpace(parts[1])
	if token == "" {
		return "", false
	}
	return token, true
}

package middleware

import (
	"crypto/rand"
	"encoding/hex"
	"net/http"
)

const requestIDHeader = "X-Request-ID"

// RequestID injects a unique request ID into the response header and request context.
// If the client sends an X-Request-ID header, it is passed through; otherwise a new ID is generated.
func RequestID(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		id := r.Header.Get(requestIDHeader)
		if id == "" {
			id = newRequestID()
		}
		w.Header().Set(requestIDHeader, id)
		next.ServeHTTP(w, r.WithContext(withRequestID(r.Context(), id)))
	})
}

// GetRequestID retrieves the request ID from the context. Returns empty string if not set.
func GetRequestID(r *http.Request) string {
	return requestIDFromContext(r.Context())
}

func newRequestID() string {
	b := make([]byte, 8)
	_, _ = rand.Read(b)
	return hex.EncodeToString(b)
}

