package db

import (
	"context"
	"fmt"
	"log/slog"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

// Connect establishes a connection pool to the database with retry logic.
func Connect(ctx context.Context, databaseURL string) (*pgxpool.Pool, error) {
	var pool *pgxpool.Pool
	var err error

	for attempt := 1; attempt <= 3; attempt++ {
		pool, err = pgxpool.New(ctx, databaseURL)
		if err != nil {
			slog.Warn("db: connection attempt failed",
				"attempt", attempt,
				"error", err,
			)
			if attempt < 3 {
				time.Sleep(time.Duration(attempt) * time.Second)
			}
			continue
		}

		if err = pool.Ping(ctx); err != nil {
			pool.Close()
			slog.Warn("db: ping failed",
				"attempt", attempt,
				"error", err,
			)
			if attempt < 3 {
				time.Sleep(time.Duration(attempt) * time.Second)
			}
			continue
		}

		slog.Info("db: connected", "attempt", attempt)
		return pool, nil
	}

	return nil, fmt.Errorf("db: failed to connect after 3 attempts: %w", err)
}

package server

import (
	"context"
	"net/http"
	"time"
)

const (
	readTimeout       = 15 * time.Second
	writeTimeout      = 30 * time.Second
	idleTimeout       = 60 * time.Second
	readHeaderTimeout = 5 * time.Second
)

// Server wraps an http.Server with production-grade timeouts.
type Server struct {
	httpServer *http.Server
}

// New constructs a Server with production timeouts.
func New(addr string, handler http.Handler) *Server {
	return &Server{
		httpServer: &http.Server{
			Addr:              addr,
			Handler:           handler,
			ReadTimeout:       readTimeout,
			WriteTimeout:      writeTimeout,
			IdleTimeout:       idleTimeout,
			ReadHeaderTimeout: readHeaderTimeout,
		},
	}
}

// Start begins listening and serving HTTP requests. It blocks until the
// server is shut down or encounters an error.
func (s *Server) Start() error {
	return s.httpServer.ListenAndServe()
}

// Shutdown gracefully drains in-flight requests within the given context.
func (s *Server) Shutdown(ctx context.Context) error {
	return s.httpServer.Shutdown(ctx)
}

